import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.io.Reader;
import java.io.StringReader;

import static org.junit.jupiter.api.Assertions.*;

public class Parser_parseInput_1_Test {

    @Test
    @DisplayName("String overload with real HTML parser returns Document with expected element structure")
    public void test_TC07() {
        // GIVEN: using HTML parser to exercise HTML-specific TreeBuilder branch (path through HTML parse logic)
        Parser parser = Parser.htmlParser();
        String html = "<html><body><p>Test</p></body></html>";
        String baseUri = "http://example.com";
        // WHEN: call string overload -> goes to parseInput(String, String) then Reader overload then HTML TreeBuilder
        Document doc = parser.parseInput(html, baseUri);
        // THEN: the <p> element must be parsed in body and baseUri preserved
        Element p = doc.body().selectFirst("p");
        assertNotNull(p, "Expected a <p> element in the body");
        assertEquals("Test", p.text(), "The text of the <p> element should be 'Test'");
        assertEquals(baseUri, doc.baseUri(), "Base URI should match the provided value");
    }

    @Test
    @DisplayName("Reader overload with real XML parser returns Document whose root is <root>")
    public void test_TC08() throws Exception {
        // GIVEN: using XML parser to exercise XML TreeBuilder branch (path through XML parse logic)
        Parser parser = Parser.xmlParser();
        Reader reader = new StringReader("<root><child/></root>");
        String baseUri = "urn:test";
        // WHEN: call Reader overload -> goes to parseInput(Reader, String) then XML TreeBuilder
        Document doc = parser.parseInput(reader, baseUri);
        // THEN: root element tag name must be "root", child parsed, and baseUri preserved
        // Since Document.documentElement() is not public in Jsoup, get the first child of the Document
        Element root = doc.child(0);
        assertEquals("root", root.tagName(), "Root element name should be 'root'");
        Elements children = doc.select("child"); // Changed List<Node> to Elements
        assertEquals(1, children.size(), "There should be exactly one <child> element");
        assertEquals(baseUri, doc.baseUri(), "Base URI should match the provided value");
    }

    @Test
    @DisplayName("String overload with real HTML parser and null baseUri returns Document with empty baseUri")
    public void test_TC09() {
        // GIVEN: HTML parser, null baseUri triggers boundary logic for baseUri handling
        Parser parser = Parser.htmlParser();
        String html = "<div>Edge</div>";
        String baseUri = null;
        // WHEN: parseInput with null baseUri -> should treat null as empty string per intended design
        Document doc = parser.parseInput(html, baseUri);
        // THEN: the <div> is parsed and baseUri is normalized to empty string
        Element div = doc.body().selectFirst("div");
        assertNotNull(div, "Expected a <div> element in the body");
        assertEquals("Edge", div.text(), "The text of the <div> element should be 'Edge'");
        assertEquals("", doc.baseUri(), "Base URI should be empty string when provided null");
    }
}
